+    #[test]
+    fn table_state_scroll_down_is_overflow_safe() {
+        // Ensure `scroll_down` cannot wrap on invalid persisted offsets.
+        let mut state = TableState {
+            offset: usize::MAX - 1,
+            ..Default::default()
+        };
+        state.scroll_down(10, 100);
+        assert_eq!(state.offset, 99);
